import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Container, Row, Col, Card, Form, Button, Alert } from 'react-bootstrap';
import { useAuth } from '../contexts/AuthContext';
import { RegisterData } from '../types';

export const Register: React.FC = () => {
  const [formData, setFormData] = useState<RegisterData>({
    nombre: '',
    correo: '',
    password: '',
    password_confirm: '',
    telefono: '',
  });
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [validated, setValidated] = useState(false);
  const [passwordStrength, setPasswordStrength] = useState({
    length: false,
    match: false,
  });

  const { register, isAuthenticated, loading, error } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (isAuthenticated) {
      navigate('/', { replace: true });
    }
  }, [isAuthenticated, navigate]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));

    // Validar contraseña en tiempo real
    if (name === 'password' || name === 'password_confirm') {
      const password = name === 'password' ? value : formData.password;
      const confirmPassword = name === 'password_confirm' ? value : formData.password_confirm;

      setPasswordStrength({
        length: password.length >= 8,
        match: password === confirmPassword && password.length > 0,
      });
    }
  };

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const form = e.currentTarget;

    if (form.checkValidity() === false) {
      e.stopPropagation();
      setValidated(true);
      return;
    }

    if (formData.password !== formData.password_confirm) {
      return;
    }

    await register(formData);
  };

  const togglePassword = () => {
    setShowPassword(!showPassword);
  };

  const toggleConfirmPassword = () => {
    setShowConfirmPassword(!showConfirmPassword);
  };

  return (
    <div className="min-vh-100 d-flex align-items-center bg-light py-4">
      <Container>
        <Row className="justify-content-center">
          <Col md={8} lg={6}>
            <Card className="shadow">
              <Card.Body className="p-4">
                <div className="text-center mb-4">
                  <i className="bi bi-person-plus text-primary" style={{ fontSize: '4rem' }}></i>
                  <h3 className="mt-3">Crear Cuenta</h3>
                  <p className="text-muted">Únete a MuebleClick y descubre los mejores muebles</p>
                </div>

                {error && (
                  <Alert variant="danger" className="mb-4">
                    <i className="bi bi-exclamation-triangle"></i> {error}
                  </Alert>
                )}

                <Form noValidate validated={validated} onSubmit={handleSubmit}>
                  <Row>
                    <Col md={6}>
                      <Form.Group className="mb-3" controlId="nombre">
                        <Form.Label>Nombre Completo</Form.Label>
                        <Form.Control
                          type="text"
                          name="nombre"
                          value={formData.nombre}
                          onChange={handleChange}
                          placeholder="Tu nombre"
                          required
                          autoComplete="name"
                        />
                        <Form.Control.Feedback type="invalid">
                          Por favor, ingresa tu nombre completo.
                        </Form.Control.Feedback>
                      </Form.Group>
                    </Col>
                    <Col md={6}>
                      <Form.Group className="mb-3" controlId="telefono">
                        <Form.Label>Teléfono</Form.Label>
                        <Form.Control
                          type="tel"
                          name="telefono"
                          value={formData.telefono}
                          onChange={handleChange}
                          placeholder="55-1234-5678"
                          autoComplete="tel"
                        />
                      </Form.Group>
                    </Col>
                  </Row>

                  <Form.Group className="mb-3" controlId="correo">
                    <Form.Label>Correo Electrónico</Form.Label>
                    <Form.Control
                      type="email"
                      name="correo"
                      value={formData.correo}
                      onChange={handleChange}
                      placeholder="tu@email.com"
                      required
                      autoComplete="email"
                    />
                    <Form.Control.Feedback type="invalid">
                      Por favor, ingresa un correo electrónico válido.
                    </Form.Control.Feedback>
                  </Form.Group>

                  <Row>
                    <Col md={6}>
                      <Form.Group className="mb-3" controlId="password">
                        <Form.Label>Contraseña</Form.Label>
                        <div className="input-group">
                          <Form.Control
                            type={showPassword ? 'text' : 'password'}
                            name="password"
                            value={formData.password}
                            onChange={handleChange}
                            placeholder="Mínimo 8 caracteres"
                            required
                            minLength={8}
                            autoComplete="new-password"
                          />
                          <Button 
                            variant="outline-secondary" 
                            type="button"
                            onClick={togglePassword}
                          >
                            <i className={`bi ${showPassword ? 'bi-eye-slash' : 'bi-eye'}`}></i>
                          </Button>
                        </div>
                        <Form.Control.Feedback type="invalid">
                          La contraseña debe tener al menos 8 caracteres.
                        </Form.Control.Feedback>
                      </Form.Group>
                    </Col>
                    <Col md={6}>
                      <Form.Group className="mb-3" controlId="password_confirm">
                        <Form.Label>Confirmar Contraseña</Form.Label>
                        <div className="input-group">
                          <Form.Control
                            type={showConfirmPassword ? 'text' : 'password'}
                            name="password_confirm"
                            value={formData.password_confirm}
                            onChange={handleChange}
                            placeholder="Repite tu contraseña"
                            required
                            minLength={8}
                            autoComplete="new-password"
                          />
                          <Button 
                            variant="outline-secondary" 
                            type="button"
                            onClick={toggleConfirmPassword}
                          >
                            <i className={`bi ${showConfirmPassword ? 'bi-eye-slash' : 'bi-eye'}`}></i>
                          </Button>
                        </div>
                        <Form.Control.Feedback type="invalid">
                          Las contraseñas deben coincidir.
                        </Form.Control.Feedback>
                      </Form.Group>
                    </Col>
                  </Row>

                  {/* Validación de contraseña */}
                  <div className="mb-3">
                    <small className="text-muted">La contraseña debe contener:</small>
                    <div className="row mt-2">
                      <div className="col-6">
                        <small className={passwordStrength.length ? 'text-success' : 'text-muted'}>
                          <i className={`bi ${passwordStrength.length ? 'bi-check-circle-fill' : 'bi-circle'}`}></i> Mínimo 8 caracteres
                        </small>
                      </div>
                      <div className="col-6">
                        <small className={passwordStrength.match ? 'text-success' : 'text-muted'}>
                          <i className={`bi ${passwordStrength.match ? 'bi-check-circle-fill' : 'bi-circle'}`}></i> Las contraseñas coinciden
                        </small>
                      </div>
                    </div>
                  </div>

                  <Form.Group className="mb-3" controlId="terminos">
                    <Form.Check 
                      type="checkbox" 
                      label="Acepto los términos y condiciones y la política de privacidad" 
                      required
                    />
                  </Form.Group>

                  <Form.Group className="mb-3" controlId="newsletter">
                    <Form.Check 
                      type="checkbox" 
                      label="Deseo recibir ofertas y novedades por correo electrónico" 
                    />
                  </Form.Group>

                  <div className="d-grid gap-2">
                    <Button 
                      variant="primary" 
                      type="submit" 
                      size="lg"
                      disabled={loading}
                    >
                      {loading ? (
                        <>
                          <span className="spinner-border spinner-border-sm me-2"></span>
                          Creando cuenta...
                        </>
                      ) : (
                        <>
                          <i className="bi bi-person-plus"></i> Crear Cuenta
                        </>
                      )}
                    </Button>
                  </div>
                </Form>

                <hr className="my-4" />

                <div className="text-center">
                  <p className="mb-2">¿Ya tienes una cuenta?</p>
                  <Button 
                    variant="outline-primary" 
                    href="/login"
                    className="w-100"
                  >
                    <i className="bi bi-box-arrow-in-right"></i> Iniciar Sesión
                  </Button>
                </div>
              </Card.Body>
            </Card>
          </Col>
        </Row>
      </Container>
    </div>
  );
};
